const UI_VERSION = "fbdb2aa9";

export async function handleGetUI(opts?: { apiKey?: string; version?: string; sentryDsn?: string }): Promise<Response> {
  let body = HTML_TEMPLATE;
  const scripts: string[] = [];
  if (opts?.apiKey) {
    const safe = opts.apiKey
      .replace(/\\/g, "\\\\")
      .replace(/"/g, '\\"')
      .replace(/</g, "\\x3c")
      .replace(/>/g, "\\x3e")
      .replace(/\n/g, "\\n");
    scripts.push(`window.__MA_API_KEY__="${safe}";`);
  }
  if (opts?.version) {
    scripts.push(`window.__MA_VERSION__="${opts.version}";`);
  }
  if (opts?.sentryDsn) {
    scripts.push(`window.__MA_SENTRY_DSN__="${opts.sentryDsn}";`);
  }
  body = body.replace(
    "__INJECT__",
    scripts.length > 0 ? `<script>${scripts.join("")}</script>` : "",
  );
  return new Response(body, {
    headers: {
      "Content-Type": "text/html; charset=utf-8",
      "Cache-Control": "no-store, no-cache, must-revalidate, max-age=0",
      Pragma: "no-cache",
      Expires: "0",
      ETag: `"${UI_VERSION}"`,
    },
  });
}
